	struct Answer {
		/* 需自行添加需要维护的变量 */
		int ans;
		Answer() :ans(0) {};
		Answer(int x) :ans(x) {};
	};

	Answer current_ans;
	vector<Answer> ans;

	/* 需自行修改 add del init 函数，处理相应需要维护的变量及其初始化 */
	vector<int> cnt;
	vector<int> a;
	int tot = 0;
	void init() {
		cnt.assign(n + 1, 0);
		a.assign(n + 1, 0);
		current_ans = 1;
	}

	// 扩展区间时加入元素
	void add(int pos) {
		cnt[a[pos]]++;
		if (cnt[a[pos]] == 2) {
			tot++;
			if (tot >= 1)current_ans = 0;
		}
	}

	// 缩小区间时删除元素
	void del(int pos) {
		cnt[a[pos]]--;
		if (cnt[a[pos]] == 1) {
			tot--;
			if (tot == 0)current_ans = 1;
		}
	}
